230	static void ibus_rime_update_status(IBusRimeEngine *rime_engine,
231	                                    RimeStatus *status)
232	{
233	  if (status &&
234	      rime_engine->status.is_disabled == status->is_disabled &&
235	      rime_engine->status.is_ascii_mode == status->is_ascii_mode &&
236	      rime_engine->status.schema_id && status->schema_id &&
237	      !strcmp(rime_engine->status.schema_id, status->schema_id)) {
238	    // no updates
239	    return;
240	  }
241	
242	  rime_engine->status.is_disabled = status ? status->is_disabled : False;
243	  rime_engine->status.is_ascii_mode = status ? status->is_ascii_mode : False;
244	  if (rime_engine->status.schema_id) {
245	    g_free(rime_engine->status.schema_id);
246	  }
247	  rime_engine->status.schema_id =
248	      status && status->schema_id ? g_strdup(status->schema_id) : NULL;
249	
250	  IBusProperty* prop = ibus_prop_list_get(rime_engine->props, 0);
251	  const gchar* icon;
252	  IBusText* label;
253	  if (prop) {
254	    if (!status || status->is_disabled) {
255	      icon = IBUS_RIME_ICONS_DIR "/disabled.png";
256	      label = ibus_text_new_from_static_string("維護");
257	    }
258	    else if (status->is_ascii_mode) {
259	      icon = IBUS_RIME_ICONS_DIR "/abc.png";
260	      label = ibus_text_new_from_static_string("Abc");
261	    }
262	    else {
263	      icon = IBUS_RIME_ICONS_DIR "/zh.png";
264	      /* schema_name is ".default" in switcher */
265	      if (status->schema_name && status->schema_name[0] != '.') {
266	        label = ibus_text_new_from_string(status->schema_name);
267	      }
268	      else {
269	        label = ibus_text_new_from_static_string("中文");
270	      }
271	    }
272	    if (status && !status->is_disabled && ibus_text_get_length(label) > 0) {
273	      gunichar c = g_utf8_get_char(ibus_text_get_text(label));
274	      IBusText* symbol = ibus_text_new_from_unichar(c);
275	      ibus_property_set_symbol(prop, symbol);
276	    }
277	    ibus_property_set_icon(prop, icon);
278	    ibus_property_set_label(prop, label);
279	    ibus_engine_update_property((IBusEngine *)rime_engine, prop);
280	  }
281	}
