283	static void ibus_rime_engine_update(IBusRimeEngine *rime_engine)
284	{
285	  // update properties
286	  RIME_STRUCT(RimeStatus, status);
287	  if (rime_api->get_status(rime_engine->session_id, &status)) {
288	    ibus_rime_update_status(rime_engine, &status);
289	    rime_api->free_status(&status);
290	  }
291	  else {
292	    ibus_rime_update_status(rime_engine, NULL);
293	  }
294	
295	  // commit text
296	  RIME_STRUCT(RimeCommit, commit);
297	  if (rime_api->get_commit(rime_engine->session_id, &commit)) {
298	    IBusText *text;
299	    text = ibus_text_new_from_string(commit.text);
300	    // the text object will be released by ibus
301	    ibus_engine_commit_text((IBusEngine *)rime_engine, text);
302	    rime_api->free_commit(&commit);
303	  }
304	
305	  // begin updating UI
306	
307	  RIME_STRUCT(RimeContext, context);
308	  if (!rime_api->get_context(rime_engine->session_id, &context) ||
309	      context.composition.length == 0) {
310	    ibus_engine_hide_preedit_text((IBusEngine *)rime_engine);
311	    ibus_engine_hide_auxiliary_text((IBusEngine *)rime_engine);
312	    ibus_engine_hide_lookup_table((IBusEngine *)rime_engine);
313	    rime_api->free_context(&context);
314	    return;
315	  }
316	
317	  IBusText* inline_text = NULL;
318	  IBusText* auxiliary_text = NULL;
319	  guint inline_cursor_pos = 0;
320	  int preedit_offset = 0;
321	
322	  const gboolean has_highlighted_span =
323	      (context.composition.sel_start < context.composition.sel_end);
324	
325	  // display preview text inline, if the commit_text_preview API is supported.
326	  if (g_ibus_rime_settings.embed_preedit_text &&
327	      g_ibus_rime_settings.preedit_style == PREEDIT_STYLE_PREVIEW &&
328	      RIME_STRUCT_HAS_MEMBER(context, context.commit_text_preview) &&
329	      context.commit_text_preview) {
330	    inline_text = ibus_text_new_from_string(context.commit_text_preview);
331	    const guint inline_text_len = ibus_text_get_length(inline_text);
332	    inline_cursor_pos =
333	        g_ibus_rime_settings.cursor_type == CURSOR_TYPE_SELECT ?
334	        g_utf8_strlen(context.composition.preedit,
335	                      context.composition.sel_start) :
336	        inline_text_len;
337	    inline_text->attrs = ibus_attr_list_new();
338	    ibus_attr_list_append(
339	        inline_text->attrs,
340	        ibus_attr_underline_new(
341	            IBUS_ATTR_UNDERLINE_SINGLE, 0, inline_text_len));
342	    // show the unconverted range of preedit text as auxiliary text
343	    if (has_highlighted_span) {
344	      preedit_offset = context.composition.sel_start;
345	      if (g_ibus_rime_settings.color_scheme) {
346	        const guint start = g_utf8_strlen(
347	            context.composition.preedit, context.composition.sel_start);
348	        const guint end = inline_text_len;
349	        ibus_attr_list_append(
350	            inline_text->attrs,
351	            ibus_attr_foreground_new(
352	                g_ibus_rime_settings.color_scheme->text_color, start, end));
353	        ibus_attr_list_append(
354	            inline_text->attrs,
355	            ibus_attr_background_new(
356	                g_ibus_rime_settings.color_scheme->back_color, start, end));
357	      }
358	    } else {
359	      // hide auxiliary text
360	      preedit_offset = context.composition.length;
361	    }
362	  }
363	  // display preedit text inline
364	  else if (g_ibus_rime_settings.embed_preedit_text &&
365	           g_ibus_rime_settings.preedit_style == PREEDIT_STYLE_COMPOSITION) {
366	    inline_text = ibus_text_new_from_string(context.composition.preedit);
367	    const guint inline_text_len = ibus_text_get_length(inline_text);
368	    inline_cursor_pos =
369	        g_ibus_rime_settings.cursor_type == CURSOR_TYPE_SELECT ?
370	        g_utf8_strlen(context.composition.preedit,
371	                      context.composition.sel_start) :
372	        g_utf8_strlen(context.composition.preedit,
373	                      context.composition.cursor_pos);
374	    inline_text->attrs = ibus_attr_list_new();
375	    ibus_attr_list_append(
376	        inline_text->attrs,
377	        ibus_attr_underline_new(
378	            IBUS_ATTR_UNDERLINE_SINGLE, 0, inline_text_len));
379	    if (has_highlighted_span && g_ibus_rime_settings.color_scheme) {
380	      const guint start = g_utf8_strlen(
381	          context.composition.preedit, context.composition.sel_start);
382	      const glong end = g_utf8_strlen(
383	          context.composition.preedit, context.composition.sel_end);
384	      ibus_attr_list_append(
385	          inline_text->attrs,
386	          ibus_attr_foreground_new(
387	              g_ibus_rime_settings.color_scheme->text_color, start, end));
388	      ibus_attr_list_append(
389	          inline_text->attrs,
390	          ibus_attr_background_new(
391	              g_ibus_rime_settings.color_scheme->back_color, start, end));
392	    }
393	    preedit_offset = context.composition.length;
394	  }
395	
396	  // calculate auxiliary text
397	  if (preedit_offset < context.composition.length) {
398	    const char* preedit = context.composition.preedit + preedit_offset;
399	    auxiliary_text = ibus_text_new_from_string(preedit);
400	    // glong preedit_len = g_utf8_strlen(preedit, -1);
401	    // glong cursor_pos = g_utf8_strlen(
402	    //    preedit, context.composition.cursor_pos - preedit_offset);
403	    if (has_highlighted_span) {
404	      auxiliary_text->attrs = ibus_attr_list_new();
405	      const glong start = g_utf8_strlen(
406	          preedit, context.composition.sel_start - preedit_offset);
407	      const glong end = g_utf8_strlen(
408	          preedit, context.composition.sel_end - preedit_offset);
409	      ibus_attr_list_append(
410	          auxiliary_text->attrs,
411	          ibus_attr_foreground_new(RIME_COLOR_BLACK, start, end));
412	      ibus_attr_list_append(
413	          auxiliary_text->attrs,
414	          ibus_attr_background_new(RIME_COLOR_LIGHT, start, end));
415	    }
416	  }
417	
418	  if (inline_text) {
419	    ibus_engine_update_preedit_text(
420	        (IBusEngine *)rime_engine, inline_text, inline_cursor_pos, TRUE);
421	  } else {
422	    ibus_engine_hide_preedit_text((IBusEngine *)rime_engine);
423	  }
424	  if (auxiliary_text) {
425	    ibus_engine_update_auxiliary_text(
426	        (IBusEngine *)rime_engine, auxiliary_text, TRUE);
427	  } else {
428	    ibus_engine_hide_auxiliary_text((IBusEngine *)rime_engine);
429	  }
430	
431	  ibus_lookup_table_clear(rime_engine->table);
432	  if (context.menu.num_candidates) {
433	    int i;
434	    int num_select_keys =
435	        context.menu.select_keys ? strlen(context.menu.select_keys) : 0;
436	    gboolean has_labels =
437	        RIME_STRUCT_HAS_MEMBER(context, context.select_labels) &&
438	        context.select_labels;
439	    gboolean has_page_down = !context.menu.is_last_page;
440	    gboolean has_page_up =
441	        context.menu.is_last_page && context.menu.page_no > 0;
442	    ibus_lookup_table_set_round(
443	        rime_engine->table,
444	        !(context.menu.is_last_page || context.menu.page_no == 0));
445	    ibus_lookup_table_set_page_size(rime_engine->table, context.menu.page_size);
446	    if (has_page_up) { //show page up for last page
447	      for (i = 0; i < context.menu.page_size; ++i) {
448	        ibus_lookup_table_append_candidate(
449	            rime_engine->table, ibus_text_new_from_string(""));
450	      }
451	    }
452	    for (i = 0; i < context.menu.num_candidates; ++i) {
453	      gchar* text = context.menu.candidates[i].text;
454	      gchar* comment = context.menu.candidates[i].comment;
455	      IBusText *cand_text = NULL;
456	      if (comment) {
457	        gchar* temp = g_strconcat(text, " ", comment, NULL);
458	        cand_text = ibus_text_new_from_string(temp);
459	        g_free(temp);
460	        int text_len = g_utf8_strlen(text, -1);
461	        int end_index = ibus_text_get_length(cand_text);
462	        ibus_text_append_attribute(cand_text,
463	                                   IBUS_ATTR_TYPE_FOREGROUND,
464	                                   RIME_COLOR_DARK,
465	                                   text_len, end_index);
466	      }
467	      else {
468	        cand_text = ibus_text_new_from_string(text);
469	      }
470	      ibus_lookup_table_append_candidate(rime_engine->table, cand_text);
471	      IBusText *label = NULL;
472	      if (i < context.menu.page_size && has_labels) {
473	        label = ibus_text_new_from_string(context.select_labels[i]);
474	      }
475	      else if (i < num_select_keys) {
476	        label = ibus_text_new_from_unichar(context.menu.select_keys[i]);
477	      }
478	      else {
479	        label = ibus_text_new_from_printf("%d", (i + 1) % 10);
480	      }
481	      ibus_lookup_table_set_label(rime_engine->table, i, label);
482	    }
483	    if (has_page_down) { //show page down except last page
484	      ibus_lookup_table_append_candidate(
485	          rime_engine->table, ibus_text_new_from_string(""));
486	    }
487	    if (has_page_up) { //show page up for last page
488	      ibus_lookup_table_set_cursor_pos(
489	          rime_engine->table,
490	          context.menu.page_size + context.menu.highlighted_candidate_index);
491	    }
492	    else {
493	      ibus_lookup_table_set_cursor_pos(
494	          rime_engine->table, context.menu.highlighted_candidate_index);
495	    }
496	    ibus_lookup_table_set_orientation(
497	        rime_engine->table, g_ibus_rime_settings.lookup_table_orientation);
498	    ibus_engine_update_lookup_table(
499	        (IBusEngine *)rime_engine, rime_engine->table, TRUE);
500	  }
501	  else {
502	    ibus_engine_hide_lookup_table((IBusEngine *)rime_engine);
503	  }
504	
505	  // end updating UI
506	  rime_api->free_context(&context);
507	}
