509	static gboolean
510	ibus_rime_engine_process_key_event (IBusEngine *engine,
511	                                    guint       keyval,
512	                                    guint       keycode,
513	                                    guint       modifiers)
514	{
515	  // ignore super key, @see ibus_engine_filter_key_event
516	  if (modifiers & (IBUS_SUPER_MASK | IBUS_MOD4_MASK)) {
517	    return FALSE;
518	  }
519	  
520	  IBusRimeEngine *rime_engine = (IBusRimeEngine *)engine;
521	
522	  modifiers &= (IBUS_RELEASE_MASK | IBUS_LOCK_MASK | IBUS_SHIFT_MASK |
523	                IBUS_CONTROL_MASK | IBUS_MOD1_MASK);
524	
525	  if (!rime_api->find_session(rime_engine->session_id)) {
526	    ibus_rime_create_session(rime_engine);
527	  }
528	  if (!rime_engine->session_id) {  // service disabled
529	    ibus_rime_engine_update(rime_engine);
530	    return FALSE;
531	  }
532	
533	  // Arrow key actions respect candidate list orientation.
534	  Bool horizontal = g_ibus_rime_settings.lookup_table_orientation ==
535	                    IBUS_ORIENTATION_HORIZONTAL;
536	  if (rime_api->get_option(rime_engine->session_id, "_horizontal") != horizontal) {
537	    rime_api->set_option(rime_engine->session_id, "_horizontal", horizontal);
538	  }
539	
540	  gboolean result =
541	      rime_api->process_key(rime_engine->session_id, keyval, modifiers);
542	  ibus_rime_engine_update(rime_engine);
543	  return result;
544	}
545	
546	static void ibus_rime_engine_property_activate (IBusEngine *engine,
547	                                                const gchar *prop_name,
548	                                                guint prop_state)
549	{
550	  extern void ibus_rime_start(gboolean full_check);
551	  extern void ibus_rime_stop();
552	  IBusRimeEngine *rime_engine = (IBusRimeEngine *)engine;
553	  if (!strcmp("deploy", prop_name)) {
554	    ibus_rime_stop();
555	    ibus_rime_start(TRUE);
556	    ibus_rime_engine_update(rime_engine);
557	  }
558	  else if (!strcmp("sync", prop_name)) {
559	    // in the case a maintenance thread has already been started
560	    // by start_maintenance(); the following call to sync_user_data()
561	    // will queue data synching tasks for execution in the working
562	    // maintenance thread, and will return False.
563	    // however, there is still chance that the working maintenance thread
564	    // happens to be quitting when new tasks are added, thus leaving newly
565	    // added tasks undone...
566	    rime_api->sync_user_data();
567	    ibus_rime_engine_update(rime_engine);
568	  }
569	  else if (!strcmp("InputMode", prop_name)) {
570	    rime_api->set_option(
571	        rime_engine->session_id, "ascii_mode",
572	        !rime_api->get_option(rime_engine->session_id, "ascii_mode"));
573	    ibus_rime_engine_update(rime_engine);
574	  }
575	}
576	
577	static void ibus_rime_engine_candidate_clicked (IBusEngine *engine,
578	                                                guint index,
579	                                                guint button,
580	                                                guint state)
581	{
582	  IBusRimeEngine *rime_engine = (IBusRimeEngine *)engine;
583	  if (RIME_API_AVAILABLE(rime_api, select_candidate)) {
584	    RIME_STRUCT(RimeContext, context);
585	    if (!rime_api->get_context(rime_engine->session_id, &context) ||
586	      context.composition.length == 0) {
587	      rime_api->free_context(&context);
588	      return;
589	    }
590	    rime_api->select_candidate(
591	        rime_engine->session_id,
592	        context.menu.page_no * context.menu.page_size + index);
593	    rime_api->free_context(&context);
594	    ibus_rime_engine_update(rime_engine);
595	  }
596	}
597	
598	static void ibus_rime_engine_page_up (IBusEngine *engine)
599	{
600	    IBusRimeEngine *rime_engine = (IBusRimeEngine *)engine;
601	    rime_api->process_key(rime_engine->session_id, IBUS_KEY_Page_Up, 0);
602	    ibus_rime_engine_update(rime_engine);
603	}
604	
605	static void ibus_rime_engine_page_down (IBusEngine *engine)
606	{
607	    IBusRimeEngine *rime_engine = (IBusRimeEngine *)engine;
608	    rime_api->process_key(rime_engine->session_id, IBUS_KEY_Page_Down, 0);
609	    ibus_rime_engine_update(rime_engine);
610	}
